cations/4/title": "Université Bordeaux Montaigne", "educations/5/description": "Nagoya Daigaku (University) - Aichi Prefecture\n- 2 months of Japanese courses after 3 years of study at Bordeaux university\n- multi-cultural class\n- very interactive and high level teaching\n- exchanges with locals, life in a typical old japanese house\n- tour of the country", "educations/5/period/endedOn/month": "0", "educations/5/period/endedOn/year": "1991", "educations/5/period/startedOn/month": "0", "educations/5/period/startedOn/year": "1991", "educations/5/subtitle": "Japanese", "educations/5/title": "名古屋外語大学", "educations/6/period/endedOn/month": "0", "educations/6/period/endedOn/year": "1988", "educations/6/period/startedOn/month": "0", "educations/6/period/startedOn/year": "1986", "educations/6/subtitle": "A Levels, Physics, Maths, Biology, Languages", "educations/6/title": "Lycée Claude Bernard (Paris)", "experiences/0/companyId": "45708", "experiences/0/companyIndustry": "Hospitality", "experiences/0/companyLink1": "https://www.linkedin.com/company/wyndhamhotels/", "experiences/0/companyName": "Wyndham Hotels & Resorts", "experiences/0/companySize": "1001-5000", "experiences/0/companyUrn": "urn:li:fsd_company:45708", "experiences/0/companyWebsite": "https://corporate.wyndhamhotels.com/", "experiences/0/employmentType": "Freelance", "experiences/0/jobDescription": "•\tTrouble shooting for Wyndham Hotels & Resorts: \n\n>> Wyndham Grand Phnom Penh Capital - 830 rooms on a post opening phase: a team to build, structure to implement, 10 F&B outlets to conceptualise and open, strategies to put up, PR to unleash etc. Roll-out preopening tasks as per schedule, restructured and engaged with the thriving Cambodia Hotel Association around great networking events!\n\n>> Wyndham Garden Samui Wing (Phase 1: 260 condos, 112 hotel rooms) – design full concept for the whole condotel property (rooms, condos, wellbeing, F&B, coworking, employer branding, uniforms …), marketing strategy, established target markets, pricing, then all preopening tools (critical paths, budget with 35% yearly profit margin, salary structure, very lean organisational structure, Wyndham standards and databanks) – communications between project teams and Wyndham teams, a lot of networking to embed our new property within its community, recruitment and onboarding of the preopening team, building brand awareness on and offline", "experiences/0/jobLocationCountry": "US", "experiences/0/jobStartedOn": "12-2024", "experiences/0/jobStillWorking": "true", "experiences/0/logo": "https://media.licdn.com/dms/image/v2/C4E0BAQEI_WMf-ScVng/company-logo_400_400/company-logo_400_400/0/1631361431272/wyndhamhotels_logo?e=1778112000&v=beta&t=BR_QdDSt65BhNWKv9x_S-K5PtIkYSF4HtKELoFLubjI", "experiences/0/title": "General Manager", "experiences/1/companyId": "112998728", "experiences/1/companyLink1": "https://www.linkedin.com/company/asia-hospitality-advisors/", "experiences/1/companyName": "Asia Hospitality Advisors Co. Ltd", "experiences/1/companyUrn": "urn:li:fsd_company:112998728", "experiences/1/employmentType": "Self-employed", "experiences/1/jobDescription": "New concepts, branding, market studies, hotels interim management, transition management, turn-around operations, restructuring, re-opening, rebranding, sales & marketing, recruitment & training, audits\n\n•\tCurrent assignement: \n>> Asia Hot Homes - Developing a new inclusive property management system for condotels, setting up a new management company for condotels / boutique hotels in Cambodia \n\n•\tRecent clients: Wyndham Hotels & Resorts, Sripatum University BKK, Storm Coworking Phuket, Health Oasis resort Samui, Atheneum Berlin, Momen, Kokotel Krabi, Puri Estate / Grace Firms Bangkok, Varnabas Museum Hotel Kathmandu, Marasca/ Narai Group (Phuket), SINAE Luxury Hotel Phuket", "experiences/1/jobLocation": "Global", "experiences/1/jobStartedOn": "1-2009", "experiences/1/jobStillWorking": "true", "experiences/1/logo": "https://media