companySize": "51-200", "experiences/3/companyUrn": "urn:li:fsd_company:86698828", "experiences/3/companyWebsite": "https://sinaephuket.com/", "experiences/3/employmentType": "Full-time", "experiences/3/jobDescription": "(1 year contract before Owners decided to manage  by themselves, without the need for a GM)\n\nLuxury boutique hotel boasting 64 pool villas on the edge of the Andaman sea, with views over Koh Khai, Koh Yao Yai and Koh Phi Phi.\n\nA brand-new 5* boutique property, with 2 restaurants, 1 wine and cocktail lounge, 1 bar, our oh-so-famous Starbucks (with a view!) and a boutique Spa. \n\nOur hilltop terrace serves drinks, cocktails, amazing food and Starbucks coffees all day, with the best views in town!\n\nwww.sinaephuket.com \n- Thai team, 140 people) \n- Post opening (December ’22): restructure, rebuilding the team, setting standards, internal branding, sales & marketing (developing a junior team, sales trips overseas), keeping our concepts fresh in the market (including our Starbucks)\n- Budget: 184MB rev, 75% occupancy, THB 6,325 ADR (already THB 2,000 above), 41% flow thru to GOP / 40% to EBITDA – already achieving 50%+ conversion!", "experiences/3/jobEndedOn": "7-2023", "experiences/3/jobLocation": "Phuket, Thailand", "experiences/3/jobLocationCountry": "TH", "experiences/3/jobStartedOn": "7-2022", "experiences/3/jobStillWorking": "false", "experiences/3/logo": "https://media.licdn.com/dms/image/v2/C560BAQESNSlCBUk7DA/company-logo_400_400/company-logo_400_400/0/1671177891420/sinae_luxury_hotel_phuket_logo?e=1778112000&v=beta&t=FZ5_6XjeHcf5qQofVQqjZlX8xOSjV5X9yGuk157If1o", "experiences/3/title": "General Manager", "experiences/4/companyId": "1173961", "experiences/4/companyIndustry": "Hospitality", "experiences/4/companyLink1": "https://www.linkedin.com/company/staygenerator/", "experiences/4/companyName": "Generator", "experiences/4/companySize": "501-1000", "experiences/4/companyUrn": "urn:li:fsd_company:1173961", "experiences/4/companyWebsite": 