ier": "tanapat-kaewngam-41aa78108", "peopleAlsoViewed/23/url": "https://linkedin.com/in/ACoAABs151YBGNmMWGSsBfB3YWG5CN0ywaLjeVo", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAABem1f4BFCyLhd0VwWURfAuO_Sebc5e3By0", "peopleAlsoViewed/24/first_name": "Vugar", "peopleAlsoViewed/24/follower_count": "2393", "peopleAlsoViewed/24/headline": "Executive Chef", "peopleAlsoViewed/24/last_name": "Ismayilov", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/profile_picture": "https://media.licdn.com/dms/image/v2/D4E03AQGhzsHWanhoDQ/profile-displayphoto-crop_800_800/B4EZpQaI5bJ0AM-/0/1762285629644?e=1778112000&v=beta&t=Ac0Hlps1xgcKMqoGKr9PMSdj4MgUAw-LKNlIkiHr_4M", "peopleAlsoViewed/24/public_identifier": "vugar-ismayilov-312a83b0", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAABem1f4BFCyLhd0VwWURfAuO_Sebc5e3By0", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAABanXrIBF8iqnm_LoQeKHEkoi_7JxJZFV1s", "peopleAlsoViewed/25/first_name": "Carmine", "peopleAlsoViewed/25/follower_count": "4047", "peopleAlsoViewed/25/headline": "Director of Operations | Guest Experience, Talent Development, Financial & Commercial Management", "peopleAlsoViewed/25/last_name": "De Riso", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D4D03AQHloLIAaM9BUw/profile-displayphoto-crop_800_800/B4DZpDodHvHwAI-/0/1762071271323?e=1778112000&v=beta&t=3MulvnJ5iu_wWpd8DpoM7PUhRyELrzKbA95Cs18Rm5c", "peopleAlsoViewed/25/public_identifier": "carmine-de-riso-58234aa7", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAABanXrIBF8iqnm_LoQeKHEkoi_7JxJZFV1s", "publicIdentifier": "erwin-van-der-veen-68471642", "recommendations/0/context": "Erwin was Tunyarus's client", "recommendations/0/date": "March 16, 2024", "recommendations/0/description": "Khun Mild worked for Cypher when we had temporarily contracted them to oversee our revenue management functions, as such she was assisting us in this area.\nShe was at all times a very friendly person to deal with, whilst displaying great passion for her role within Cypher.\nOnce we took control of our Revenue management internally again, the assignment to oversee SALA ended, and we are thankful for the efforts she made in the interim period.", "recommendations/0/name": "Tunyarus Boonyaphet", "recommendations/0/subtitle": "Portfolio Revenue Manager | E-Commerce Specialist | Maximizing Profitability & Growth", "recommendations/0/url": "https://www.linkedin.com/in/tunyarus-boonyaphet-1926a716b/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAACiA0j4BKvaMsktCsTWmHeU4-1cD1QidR0g", "recommendations/1/context": "Erwin managed Vivian directly", "recommendations/1/date": "March 25, 2021", "recommendations/1/description": "Vivian has a passion for the job, worked well with peers and superiors, and a never failing desire to exceed past performance by aiming for new clients, use new resources and drive performance through her team. Based in Kuala Lumpur her presence at the (remotely located) resort was less, but during her visits to the property as and when required she always displayed a great understanding of the property team and provided support when possible, creating a great team spirit between Sales and Operations.", "recommendations/1/name": "Vivian Choa", "recommendations/1/subtitle": "Director of Sales & Marketing at Mövenpick Resort & Spa Bintan Lagoon (Pre-Opening)", "recommendations/1/url": "https://www.linkedin.com/in/vivian-choa-9022505/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAADtAhIB0D-jK8l-8kzacGqh54cJruZtmKs", "recommendations/2/context": "Erwin managed Patricia directly", "recommendations/2/date": "January 13, 2021", "recommendations/2/description": "Though not too long, I had the pleasure of having Patricia as Ast Dir Sales for AVANI Sepang. During her tenure I have had at all times positive professional interactions with Patricia, who displayed a high level of enthusiasm and integrity whilst ensuring her efforts to maximize revenues for the resort. She left us to start a higher position as part of a pre-opening team, which made sense, yet her absence was felt. I wish her all the best in her future endeavors.", "recommendations/2/name": "Patricia Santos", "recommendations/2/subtitle": "Experienced Sales & Marketing Leader", "recommendations/2/url": "https://www.linkedin.com/in/patricia-santos-salesmktg/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAAFfTUsBCxJYmYfs-HvAFW2el1gEQeXDMm0", "recommendations/3/context": "Erwin managed Sjors directly", "recommendations/3/date": "January 8, 2018", "recommendations/3/description": "Sjors was my Resident Manager whilst I was GM for AVANI Sepang Goldcoast Resort in Malaysia. The resort has a large room count and is located in a challenging environemtn, ie far away from major cities, and the workforce requires a lot of supervision. \n\nSjors has been a very hands-on manager, handling most of the Operational areas of the hotel, and he has proven himself to be a very reliable partner to me in this.\n\nIt was regrettable that Sjors left after less than a year, but he was approached by his former employer to take responsibility of the pre-opening of one of their pre-opening flagship properties, so I can fully understand the choice he made, and have no objection to endorse him for any future employer based on my professional experience with him.", "recommendations/3/name": "Sjors Martins", "recommendations/3/subtitle": "Operations Executive | Residential, Community, Lifestyle & Hospitality Operations | Real Estate, Projects & Pre-Openings | Middle East Specialist", "recommendations/3/url": "https://www.linkedin.com/in/sjorsmartins/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAF_RUUB3PcTWI5UFaACJ3aRDJNz-MJl1K4", "recommendations/4/context": "Erwin worked with Rupal on the same team", "recommendations/4/date": "January 3, 2018", "recommendations/4/description": "I had the pleasure of working with Rupal in His Lyon Al Hama, and can only say great things about her professionally as well as personally. Rupal is one of those people that when they enter a room, positive energy comes along with her!\n\nShe has since then grown to bigger and better roles, a true testimony to her Capabilities!\n\nI would love to work with her again, and g", "recommendations/4/name": "Rupal Desai", "recommendations/4/subtitle": "Reservation Manager At Waldorf Astoria DIFC (Pre-opening)", "recommendations/4/url": "https://www.linkedin.com/in/rupal-desai-b410a08a/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAABLg0GEBBI5OxxRJoPdMwDD5t71yBnKEGwI", "recommendations/5/context": "Erwin was Ruth's teacher", "recommendations/5/date": "October 4, 2017", "recommendations/5/description": "Ruth was a former colleague when we both worked at Hyatt in Dubai, her outstanding customer service skills made me recruit her when I later returned to the UAE in my capacity as pre-opening hotel manager for DTbH Ras al Khaimah. \n\nShe has been a key member of the pre-opening team, her positive attitude has greatly added to the service orientation of the whole team, most of whom were novices at the hotel but under the expert guidance by Ruth and others were able to open the hotel with great success!\n\nAside from professional recommendation I equally have no hesitance to recommend her personally, as the warmth she displays professionally is matched by her personality as an individual, a genuinely caring person!\n\nShould opportunities rise, I have no hesitation to recommend Ruth for leadership positions or work with her again in the near future.", "recommendations/5/name": "Ruth J.", "recommendations/5/subtitle": "Guest Relations Manager at DoubleTree by Hilton Ras Al Khaimah", "recommendations/5/url": "https://www.linkedin.com/in/ruth-j-63224a104/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAABpgYwYBJj3fjkn85_S5z11-YeiFrl3qhAo", "recommendations/6/context": "Erwin managed Rizan directly", "recommendations/6/date": "September 29, 2017", "recommendations/6/description": "Rizan joined me and the team at AVANI Sepang for a year, following which he left for personal reasons back to his home country. \nWe were all sad to see him leave but as his wife was giving birth obviously we understand the priority given there!\n\nRizan has always been a highly energetic, engaging and enthusiastic leader of the HR function of the hotel, his positive Can Do attitude has been contagious and has driven the people culture across the resort.\n\nIt was a delight having him on the team, and I hope to work with him again if the opportunity rises!", "recommendations/6/name": "Rizan Afeef", "recommendations/6/subtitle": "Revolutionizing International HR: Rekindling the ‘Human’ factor in Human Resources with Unmatched Emotional Intelligence for Optimal Stakeholder Success.", "recommendations/6/url": "https://www.linkedin.com/in/rizan-afeef-ab117518/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAAOVauUBqX89juYbS6M5CKOPb5TpED8PIZE", "recommendations/7/context": "Erwin managed Debarya directly", "recommendations/7/date": "September 29, 2017", "recommendations/7/description": "I brought Debarya as Executive Chef for my resort, and have had a great 2 years with him. Largely due to his input we successfully kicked of Indian destination weddings for AVANI Sepang Goldcoast Resort. \nAside from this, Debarya has proven himself to be one of the most pro-active members of the management team, volunteering to do tasks beyond his scope of work, through this greatly contributing to the hotel function as a whole.\n\nA warm person with great desire to grow and achieve bigger things, I have no hesitation to recommend him and would welcome working with him again in the future.", "recommendations/7/name": "Debarya Chakraborty", "recommendations/7/subtitle": "Area Director- North East & General Manager- Darjeeling, Sterling Holiday Resorts", "recommendations/7/url": "https://www.linkedin.com/in/debarya-chakraborty-5ba1ab1b/", "recommendations/7/urn": "urn:li:fsd_profile:ACoAAAQfM54BQvQiDOstPNhDyCtF0LlWa7BYzH0", "recommendations/8/context": "Erwin managed Pimnara directly", "recommendations/8/date": "August 13, 2016", "recommendations/8/description": "Khun Suvimon \"Jim\" is a dedicated manager, who handled the Rooms service and other areas well whilst we worked together in Hilton Bangkok.\n\nHer contribution was very positive, always ensuring not much management attention was required in her areas, as she was well in control of her department, always ensuring the level of service was as high as possible.\n\nA very friendly and outgoing person, co-operative and supportive to all in the organization.", "recommendations/8/name": "Pimnara Loa-ananchai", "recommendations/8/subtitle": "Operations Manager ที่ Starbucks Coffee (Thailand) Co,.Ltd", "recommendations/8/url": "https://www.linkedin.com/in/pimnara-loa-ananchai-59885347/", "recommendations/8/urn": "urn:li:fsd_profile:ACoAAAnp_IQBcgj-rh2DCbjLIocckUJqA4N-Ejg", "recommendations/9/context": "Erwin managed David directly", "recommendations/9/date": "August 13, 2016", "recommendations/9/description": "David is a dedicated, entrepreneurial and outgoing person to work with, taking his job very seriously whilst still maintaining a healthy team culture of fun at work as and when possible.\nA great team player who certainly knows how to \"charm\" his way into any organization in a positive manner.\n\nHis support as FOM whilst we were both employed at Hilton was much appreciated, and I am sure those that have worked with him will feel the same.\n\n", "recommendations/9/name": "David Redondo Diaz", "recommendations/9/subtitle": "Regional Operations Manager Europe | LBS EMBA", "recommendations/9/url": "https://www.linkedin.com/in/davidredondo-director-operaciones-coo/", "recommendations/9/urn": "urn:li:fsd_profile:ACoAAAF1YAIBQEd0HfzNNIAUcftrA-FQh1Yx5bs", "recommendations/10/context": "Thomas was senior to Erwin but didn't manage Erwin directly", "recommendations/10/date": "August 13, 2016", "recommendations/10/description": "Thomas is one of those superiors you will not forget, in a positive sense. \nHis drive towards quality is not matched by many, his drive for innovation is one of a kind. a fair but firm leader, who balances well the aspects of managing and motivating the human capital vs achieving the business goals. \n\nHis resilience when working towards improvement is one of the largest inspirations I have encountered, and which I will hold dearly during my career, I would welcome any opportunity to remain professionally and personally connected.\n\nIn today's business environment it is of paramount importance to maintain a high level of integrity, and Thomas is a perfect example of how to do this.\n\nFinally, my achievements to-date are largely due to the experiences I have been able to gain under the supervision of Thomas and a select few other General Managers I have had the pleasure of working for / with.", "recommendations/10/name": "Thomas Hoeborn", "recommendations/10/subtitle": "Conrad Singapore Orchard", "recommendations/10/url": "https://www.linkedin.com/in/thomas-hoeborn-2931933/", "recommendations/10/urn": "urn:li:fsd_profile:ACoAAACPas8BlDMbLKJGlMn-NvB1KMb4apkx7ww", "recommendations/11/context": "Erwin managed Lee directly", "recommendations/11/date": "October 13, 2015", "recommendations/11/description": "I had the pleasure of working with Lee as her GM during her tenure as Ast HR Manager for Hilton Al Hamra Beach & Golf Resort. Lee has always shown the greatest dedication possible to the well-being of the team members, ensuring a well-balanced approach between this and the follow through on company policies and procedures, working tirelessly to ensure the development of the property was ensured.\nLee's challenge was made harder due to the fact that the property was being re-branded from a privately managed property to a Hilton branded identity, which on the HR front always means significant change, and Lee has been an instrumental partner and advocate of this change.\nLee aside from being very professionally capable, is a warm and friendly person, who finds establishing relationships an easy thing to do, and it shows in her track records!\n\nI wish her all the very best and remain at anyone's disposal for further information / referral should this be required.\n\nErwin", "recommendations/11/name": "Lee Ingram", "recommendations/11/subtitle": "Human Resources Manager", "recommendations/11/url": "https://www.linkedin.com/in/ingramlee/", "recommendations/11/urn": "urn:li:fsd_profile:ACoAAAP-hCEBWY1mtB3A3P8eEaLH2jGdcQemxHI", "recommendations/12/context": "Mahmoud was senior to Erwin but didn't manage Erwin directly", "recommendations/12/date": "May 28, 2015", "recommendations/12/description": "I had the pleasure of indirectly working with Mahmoud, though my employment with Hilton was outside his region. \nFortunately I had some more professional interactions with him during his 2nd posting as VP Ops KSA, and my meetings with him were always an honest reflection of his valued opinion. \n\nHe \"Walked the Talk\", not only advocated but also lived the company values, and always made time for people, irrespective of rank or title. \n\nFirm but fair would be a perfect description for him in my opinion, which I am sure other subordinates, peers and superiors will equally confirm.", "recommendations/12/name": "Mahmoud Mokhtar", "recommendations/12/subtitle": "Senior Director Focused Service Operations - MEA", "recommendations/12/url": "https://www.linkedin.com/in/mahmoudmokhtar/", "recommendations/12/urn": "urn:li:fsd_profile:ACoAAApjoWABcIadeVgyRGBO5HRvdOHmvkyTaag", "recommendations/13/context": "Erwin reported directly to Michael", "recommendations/13/date": "March 5, 2015", "recommendations/13/description": "Though long time ago, I had the pleasure of working for Michael. \nI was a Management Trainee in his department whilst in Seoul, and through his dedication to the job, professional expertise and personal attitude, he has made an impact on me which has lasted throughout my career, which has now led me to be GM for a 5-star operation. \nHis personal involvement in my development during that time will remain a fond memory for long time to come, and bares witness to his excellent people skills.\n\nHopeful that our paths will cross again in the near future, I wish him the very best and congratulate any (future) employer for having him!", "recommendations/13/name": "Michael Koltes", "recommendations/13/subtitle": "Hotelier now dedicating time to new adventures", "recommendations/13/url": "https://www.linkedin.com/in/michaelkoltes/", "recommendations/13/urn": "urn:li:fsd_profile:ACoAABFqKaUBo6lXAJNpKNRHzt5Ws9ieUpOSOew", "recommendations/14/context": "Erwin was senior to Tuhina but didn't manage Tuhina directly", "recommendations/14/date": "December 18, 2014", "recommendations/14/description": "Having had the pleasure of working with Tuhina during the refurbishment of Hilton Al Hamra Beach & Golf Resort, it was great to tap into her expertise and enthusiasm; obviously her reputation and influence are already crossing borders! The expectations of the resorts conversion were immense and Tuhina excelled in her contributions and hard work to make it happen most successfully. While wearing several hats for the cluster Hilton properties, Tuhina has always extended her cooperation, taking on tasks that were both challenging and new, with ease. I have always been impressed by her positive attitude and dedication. \n\nI have no hesitation in recommending this vibrant, energetic lady to any employer, and would be delighted for future opportunities to work with her again.", "recommendations/14/name": "Tuhina Rahman", "recommendations/14/subtitle": "Global Marketer | Ex-IHG | Ex-Hilton", "recommendations/14/url": "https://www.linkedin.com/in/tuhinarahman/", "recommendations/14/urn": "urn:li:fsd_profile:ACoAAAuiI5MBhHrwBYQjk5Rbxp2m9ABD4_TsMyI", "recommendations/15/context": "Erwin worked with Ronaldo but they were at different companies", "recommendations/15/date": "July 1, 2014", "recommendations/15/description": "I have had the pleasure of working with Ronaldo whilst his Seawings planes landed at our hotel, and together we very productively worked towards deals that would satisfy our guests as well as mutual business needs, creating a win-win situation for both companies.\nRonaldo has always remained a very hospitable, sales focused and highly energetic professional, and working with him has always been a pleasure!", "recommendations/15/name": "Ronaldo Pinho", "recommendations/15/subtitle": "Business Development Manager | Sales & Marketing Manager | Key Client Relationships | Key Account Management | Problem Solving", "recommendations/15/url": "https://www.linkedin.com/in/ronaldo-pinho30682/", "recommendations/15/urn": "urn:li:fsd_profile:ACoAAAsWvI4B0lSoJow7Sq8qX5D2SxBJx8Dyy_E", "recommendations/16/context": "Erwin was senior to Grace Megumi B. but didn't manage Grace Megumi B. directly", "recommendations/16/date": "April 10, 2013", "recommendations/16/description": "Grace was the source of knowledge and experience for everyone that worked with her, and I am sure that all her direct superiors, General Managers for Hilton Nagoya, will confirm that without Grace their offices would have been far less organized, their organization less controlled and streamlined, and the operation less successful if she would not have been in charge.\nI often wonder though, who was really in charge in the GM Office? Was it really the GM's, or was there a Gracious directive in their management???????", "recommendations/16/name": "Grace Megumi B. Gonzales", "recommendations/16/subtitle": "PA to the General Manager at Hilton Nagoya", "recommendations/16/url": "https://www.linkedin.com/in/grace-megumi-b-gonzales-48a27914/", "recommendations/16/urn": "urn:li:fsd_profile:ACoAAALjDmoBqLkqHtAz-rjy_1y57I_E_MDS-ME", "recommendations/17/context": "Erwin reported directly to Stephane", "recommendations/17/date": "November 17, 2011", "recommendations/17/description": "Very pleasant to work with Stephane, good interaction!", "recommendations/17/name": "Stephane Compagnon", "recommendations/17/subtitle": "Hotel General Manager with 20+years international experience | Board Member | Founder of Guest Pulse sarl | Helping businesses boost their online reputation to appear on Chat GPT and all AI | Free Audit available in DM", "recommendations/17/url": "https://www.linkedin.com/in/stephane-compagnon/", "recommendations/17/urn": "urn:li:fsd_profile:ACoAAABP-jkBC8wg9am2BwU_1qtXYRKC_FzT6fM", "recommendationsReceived/0/context": "Erwin was senior to Patricia but didn't manage Patricia directly", "recommendationsReceived/0/date": "January 14, 2021", "recommendationsReceived/0/description": "I had the privilege to work with Erwin in Avani Sepang, Malaysia.  Although I did not report to him directly, I learned much from his leadership style.  He walked his talk and led enthusiastically by example.  Challenges were resolved and victories were celebrated as a team and no man was an island.    \n\nWith such outstanding commitment, Erwin is great asset to any Management team. ", "recommendationsReceived/0/name": "Patricia Santos", "recommendationsReceived/0/subtitle": "Experienced Sales & Marketing Leader", "recommendationsReceived/0/url": "https://www.linkedin.com/in/patricia-santos-salesmktg/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAAFfTUsBCxJYmYfs-HvAFW2el1gEQeXDMm0", "recommendationsReceived/1/context": "Sjors reported directly to Erwin", "recommendationsReceived/1/date": "October 11, 2017", "recommendationsReceived/1/description": "It was a great pleasure working for Erwin. He is a very hands-on leader who always involves the team in his decision making. He dedicates himself to teaching the department heads while learning from their expertise as well. I truly admire his resilience. Even if there is no light at the end of the tunnel, he will never give up and gives his all.", "recommendationsReceived/1/name": "Sjors Martins", "recommendationsReceived/1/subtitle": "Operations Executive | Residential, Community, Lifestyle & Hospitality Operations | Real Estate, Projects & Pre-Openings | Middle East Specialist", "recommendationsReceived/1/url": "https://www.linkedin.com/in/sjorsmartins/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAF_RUUB3PcTWI5UFaACJ3aRDJNz-MJl1K4", "recommendationsReceived/2/context": "Rupal reported directly to Erwin", "recommendationsReceived/2/date": "October 6, 2017", "recommendationsReceived/2/description": "\" I thoroughly enjoyed my time working with Erwin. honest, dependable and impressive problem solver. As dedicated and knowledgeable manager and above all Erwin is a great person. Great beneficial asset to the company\"", "recommendationsReceived/2/name": "Rupal Desai", "recommendationsReceived/2/subtitle": "Reservation Manager At Waldorf Astoria DIFC (Pre-opening)", "recommendationsReceived/2/url": "https://www.linkedin.com/in/rupal-desai-b410a08a/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAABLg0GEBBI5OxxRJoPdMwDD5t71yBnKEGwI", "recommendationsReceived/3/context": "Mohab managed Erwin directly", "recommendationsReceived/3/date": "October 6, 2017", "recommendationsReceived/3/description": "A true opening vet , despite the fact he was running the Hilton Ras al Khaimah,  he manged to do a great opening for the DT Ras al khaimah,  he manged to create a solid team set strong standards in place that the Hotel is benefiting from till Today, a great leader respected by the team.", "recommendationsReceived/3/name": "Mohab Ghali", "recommendationsReceived/3/subtitle": "General manager at Artic international", "recommendationsReceived/3/url": "https://www.linkedin.com/in/mohab-ghali-7b484217/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAOBZfgBOvAgfws6HWyjtPH7_lRfHvh-8BQ", "recommendationsReceived/4/context": "Debarya reported directly to Erwin", "recommendationsReceived/4/date": "September 29, 2017", "recommendationsReceived/4/description": "The bespoke General Manager with whom I had the pleasure to work under his leadership for 2 years. A great mentor and a motivator giving an upbeat to perform at the highest level. His attention to details along with genuine care for internal and external guests was fantastic. His CAN DO attitude encouraged me and the team to yield better results. Will be definitely looking forward to work with him in near future. ", "recommendationsReceived/4/name": "Debarya Chakraborty", "recommendationsReceived/4/subtitle": "Area Director- North East & General Manager- Darjeeling, Sterling Holiday Resorts", "recommendationsReceived/4/url": "https://www.linkedin.com/in/debarya-chakraborty-5ba1ab1b/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAQfM54BQvQiDOstPNhDyCtF0LlWa7BYzH0", "recommendationsReceived/5/context": "Stephane managed Erwin directly", "recommendationsReceived/5/date": "July 6, 2012", "recommendationsReceived/5/description": "Erwin managed a large multi operation in Hilton Abuja, running well over 150 team members, several outlets and a congress hall. He ran the operation smoothly in a challenging environment, balancing authority with a great people skills. Unsurprisingly, Erwin successfully progressed further in the company.", "recommendationsReceived/5/name": "Stephane Compagnon", "recommendationsReceived/5/subtitle": "Hotel General Manager with 20+years international experience | Board Member | Founder of Guest Pulse sarl | Helping businesses boost their online reputation to appear on Chat GPT and all AI | Free Audit available in DM", "recommendationsReceived/5/url": "https://www.linkedin.com/in/stephane-compagnon/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAAABP-jkBC8wg9am2BwU_1qtXYRKC_FzT6fM", "skills/0/title": "Executive Management", "skills/1/title": "Business Developmen